program.STSource:
(* initialisation of feeder *)

if fe (Mixing_done)
	then
	feeder_state:=material_a_value+material_b_value;
	reset (new_material_demand);
end_if;

(* calculating value feeder state *)

if re (forming) 
	then
	dec (feeder_state);
end_if;

if feeder_state=2 
	then
	set (new_material_demand);
end_if;

if feeder_state>2 
	then
	set (feeder_full);
	else 
	reset (feeder_full);
end_if;

if feeder_state<=2 
	then
	set (feeder_empty);
	else 
	reset (feeder_empty);
end_if;

(* initialisation of variables for forming process *)

CMeasured_temp:=int_to_real (Measured_temp);

if cmeasured_temp=setpoint_temp 
	then
	Temp_ok:=true;
	else 
	Temp_ok:=false;
end_if;

if feeder_full and not feeder_empty 
	then
	Material_ok:=true;
	else 
	Material_ok:=false;
end_if;

if not forming and not feeder_empty and re (sec) 
	then
	inc_int (material_in);
end_if;

if forming 
	then
	material_in:=0;
end_if;
